def find_method_range(src: str, class_name: str, method_name: str) -> tuple[int, int]:
    tree = ast.parse(src)
    for node in tree.body:
        if isinstance(node, ast.ClassDef) and node.name == class_name:
            for item in node.body:
                if isinstance(item, ast.FunctionDef) and item.name == method_name:
                    if item.end_lineno is None:
                        raise RuntimeError("当前 Python AST 没有 end_lineno，无法安全替换。")
                    return item.lineno, item.end_lineno
    raise RuntimeError(f"找不到 {class_name}.{method_name}")


def patch_theme() -> None:
    if not UI_THEME.exists():
        return

    s = UI_THEME.read_text(encoding="utf-8")
    backup = UI_THEME.with_suffix(".py.bak_card_editable")
    if not backup.exists():
        backup.write_text(s, encoding="utf-8")

    if '"TopPrimary.TButton"' not in s:
        marker = '    _safe_configure(style, "TNotebook"'
        if marker in s:
            s = s.replace(marker, STYLE_INSERT + "\n" + marker, 1)
        else:
            marker2 = "\ndef style_text_widget"
            s = s.replace(marker2, "\n" + STYLE_INSERT + "\n" + marker2, 1)

    # 兼容 workspace_app 仍然导入 style_canvas 的情况
    if "def style_canvas(" not in s:
        s += """

def style_canvas(canvas: tk.Canvas) -> None:
    try:
        canvas.configure(
            background=PALETTE.get("paper", "#f3eee3"),
            highlightthickness=0,
            borderwidth=0,
        )
    except Exception:
        pass
"""

    compile(s, str(UI_THEME), "exec")
    UI_THEME.write_text(s, encoding="utf-8")


def patch_workspace() -> None:
    if not WORKSPACE_APP.exists():
        raise SystemExit(f"找不到文件：{WORKSPACE_APP}")

    src = WORKSPACE_APP.read_text(encoding="utf-8")
    backup = WORKSPACE_APP.with_suffix(".py.bak_card_editable")
    backup.write_text(src, encoding="utf-8")

    if "from clawmini.ui_theme import apply_theme" in src and "style_text_widget" not in src:
        src = src.replace(
            "from clawmini.ui_theme import apply_theme",
            "from clawmini.ui_theme import apply_theme, style_text_widget",
        )

    src = src.replace(
        'self.qq_status_text.set(f"轮询待回复: {result.output.strip()[:80]}")',
        'self.qq_panel.qq_status_text.set(f"轮询待回复: {result.output.strip()[:80]}")',
    )

    old = "        self._wire_state_persistence()"
    new = '        if not hasattr(self, "search_var"):\n            self.search_var = tk.BooleanVar(value=False)\n        self._wire_state_persistence()'
    if old in src and new not in src:
        src = src.replace(old, new, 1)

    start, end = find_method_range(src, "QQAutoReplyPanel", "_build_ui")
    lines = src.splitlines()
    new_lines = lines[: start - 1] + NEW_BUILD_UI.strip("\n").splitlines() + lines[end:]
    src2 = "\n".join(new_lines) + "\n"

    compile(src2, str(WORKSPACE_APP), "exec")
    WORKSPACE_APP.write_text(src2, encoding="utf-8")


def main() -> None:
    patch_theme()
    patch_workspace()
    print("✅ 已完成：顶部胶囊按钮 + 四个可编辑状态卡 + 参数分组")
    print("备份：")
    print(f"  {WORKSPACE_APP.with_suffix('.py.bak_card_editable')}")
    print(f"  {UI_THEME.with_suffix('.py.bak_card_editable')}")
    print("下一步：")
    print("  python -m py_compile .\\src\\clawmini\\ui_theme.py")
    print("  python -m py_compile .\\src\\clawmini\\workspace_app.py")
    print("  python app.py")


if __name__ == "__main__":
    main()
